/* Full-text search over the prebuilt word index (assets/data/search-index.json,
 * generated by _scripts/build_search_index.py). Each page carries its unique
 * lowercase words; a query matches a page when every query term is contained
 * in the page's title, tags, or word list (case-insensitive substring). */
(function () {
  'use strict';

  var MAX_RESULTS = 100;
  var MIN_QUERY_LENGTH = 2;

  function preparePages(pages) {
    return pages.map(function (page) {
      return {
        title: page.title,
        url: page.url,
        tags: page.tags || [],
        titleLower: String(page.title).toLowerCase(),
        tagsLower: ' ' + (page.tags || []).join(' ').toLowerCase() + ' ',
        words: ' ' + (page.words || '') + ' '
      };
    });
  }

  /* Score one term against one page; 0 = no match. */
  function termScore(page, term) {
    var score = 0;
    if (page.titleLower.indexOf(term) !== -1) {
      score += (' ' + page.titleLower + ' ').indexOf(' ' + term + ' ') !== -1 ? 40 : 25;
    }
    if (page.tagsLower.indexOf(term) !== -1) {
      score += page.tagsLower.indexOf(' ' + term + ' ') !== -1 ? 20 : 12;
    }
    if (score > 0) return score;
    if (page.words.indexOf(' ' + term + ' ') !== -1) return 15; // exact word
    if (page.words.indexOf(' ' + term) !== -1) return 10;       // word prefix
    if (page.words.indexOf(term) !== -1) return 5;              // substring
    return 0;
  }

  function search(pages, query) {
    var terms = query.toLowerCase().split(/\s+/).filter(function (t) { return t.length > 0; });
    if (!terms.length) return [];
    var results = [];
    pages.forEach(function (page) {
      var total = 0;
      for (var i = 0; i < terms.length; i += 1) {
        var score = termScore(page, terms[i]);
        if (score === 0) return; // every term must match somewhere
        total += score;
      }
      results.push({ page: page, score: total });
    });
    results.sort(function (a, b) {
      return b.score - a.score || a.page.title.localeCompare(b.page.title);
    });
    return results;
  }

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = { preparePages: preparePages, search: search };
    return;
  }
  if (typeof document === 'undefined') return;

  function init() {
    var root = document.getElementById('site-search');
    if (!root) return;
    var input = document.getElementById('site-search-input');
    var status = document.getElementById('site-search-status');
    var list = document.getElementById('site-search-results');
    var staleNote = document.getElementById('site-search-stale');

    var pages = null;
    var idleNote = '';

    /* The page embeds the URL list of the build it belongs to; comparing it
     * with the index's URLs detects real staleness (results pointing at pages
     * this build doesn't have) without false alarms from local drafts. */
    var liveUrls = null;
    try {
      var liveUrlsEl = document.getElementById('site-search-live-urls');
      if (liveUrlsEl) liveUrls = JSON.parse(liveUrlsEl.textContent);
    } catch (e) { liveUrls = null; }

    function normalizeUrl(url) {
      try { return decodeURIComponent(url); } catch (e) { return url; }
    }

    function el(tag, className, text) {
      var node = document.createElement(tag);
      if (className) node.className = className;
      if (text !== undefined) node.textContent = text;
      return node;
    }

    function render(results, query) {
      list.innerHTML = '';
      if (!query) {
        status.textContent = 'Search ' + pages.length + ' pages. Type at least ' +
          MIN_QUERY_LENGTH + ' characters.' + idleNote;
        return;
      }
      if (!results.length) {
        status.textContent = 'No pages contain “' + query + '”.';
        return;
      }
      var shown = results.slice(0, MAX_RESULTS);
      status.textContent = results.length + (results.length === 1 ? ' page contains ' : ' pages contain ') +
        '“' + query + '”' + (results.length > shown.length ? ' — showing the first ' + shown.length : '') + '.';
      shown.forEach(function (result) {
        var item = el('li', 'site-search__result');
        var link = el('a', 'site-search__result-title', result.page.title);
        link.href = result.page.url;
        item.appendChild(link);
        item.appendChild(el('span', 'site-search__result-url', result.page.url));
        if (result.page.tags.length) {
          var tagWrap = el('span', 'site-search__result-tags');
          result.page.tags.slice(0, 6).forEach(function (tag) {
            var chip = el('a', 'tag-section__related-tag', tag);
            chip.href = (root.dataset.tagsUrl || '/tags/') + '#tag-' + tag.toLowerCase().replace(/[^a-z0-9]+/g, '-');
            tagWrap.appendChild(chip);
          });
          item.appendChild(tagWrap);
        }
        list.appendChild(item);
      });
    }

    var debounceHandle = null;
    function onInput() {
      if (debounceHandle) clearTimeout(debounceHandle);
      debounceHandle = setTimeout(function () {
        var query = input.value.trim();
        var params = new URLSearchParams(window.location.search);
        if (query) params.set('q', query); else params.delete('q');
        var qs = params.toString();
        window.history.replaceState(null, '', window.location.pathname + (qs ? '?' + qs : ''));
        if (query.length < MIN_QUERY_LENGTH) {
          render([], '');
          return;
        }
        render(search(pages, query), query);
      }, 120);
    }

    // The cache-buster ties the fetched index to this build of the page, so a
    // cached old index can never be paired with a newer page.
    fetch(root.dataset.source + '?v=' + (liveUrls ? liveUrls.length : '0'))
      .then(function (response) {
        if (!response.ok) throw new Error('HTTP ' + response.status);
        return response.json();
      })
      .then(function (data) {
        pages = preparePages(data.pages || []);
        if (Array.isArray(liveUrls)) {
          var buildSet = new Set(liveUrls.map(normalizeUrl));
          var dead = pages.filter(function (p) { return !buildSet.has(normalizeUrl(p.url)); }).length;
          if (dead > 0) staleNote.hidden = false;
          var indexSet = new Set(pages.map(function (p) { return normalizeUrl(p.url); }));
          var unindexed = liveUrls.filter(function (u) { return !indexSet.has(normalizeUrl(u)); }).length;
          if (unindexed > 0) {
            idleNote = ' ' + unindexed + (unindexed === 1 ? ' page in this build is' : ' pages in this build are') +
              ' not indexed yet (usually uncommitted drafts).';
          }
        }
        render([], '');
        input.addEventListener('input', onInput);
        input.addEventListener('keydown', function (event) {
          if (event.key === 'Escape') {
            input.value = '';
            onInput();
          }
        });
        var preset = new URLSearchParams(window.location.search).get('q');
        if (preset) {
          input.value = preset;
          render(search(pages, preset.trim()), preset.trim());
        }
        input.focus();
      })
      .catch(function (error) {
        status.textContent = 'Could not load the search index (' + error.message + ').';
      });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
